// ============================================================
// Log Entry data class
// ============================================================
data class LogEntry(
    val timestamp: Long = System.currentTimeMillis(),
    val level: LogLevel,
    val tag: String,
    val message: String,
    val throwable: Throwable? = null,
    val metadata: Map<String, Any?> = emptyMap()
) {
    enum class LogLevel { VERBOSE, DEBUG, INFO, WARN, ERROR, FATAL }

    fun formatted(): String {
        val dateFormat = SimpleDateFormat("yyyy-MM-dd HH:mm:ss.SSS", Locale.US)
        val timeStr = dateFormat.format(Date(timestamp))
        val metaStr = if (metadata.isNotEmpty()) " | metadata=$metadata" else ""
        val throwableStr = throwable?.let { "\n${getFullStackTrace(it)}" } ?: ""
        return "[$timeStr] [${level.name}] [$tag] $message$metaStr$throwableStr"
    }

    private fun getFullStackTrace(throwable: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        throwable.printStackTrace(pw)
        return sw.toString()
    }
}

// ============================================================
// Production Logger - Core logging system
// ============================================================
object ProductionLogger {

    private lateinit var appContext: Context
    private val logBuffer = ConcurrentLinkedQueue<LogEntry>()
    private val executor = Executors.newSingleThreadExecutor()
    private const val BUFFER_FLUSH_SIZE = 50
    private const val MAX_LOG_FILE_SIZE = 10 * 1024 * 1024L // 10MB
    private const val LOG_FILE_NAME = "production_logs.txt"

    fun initialize(context: Context) {
        appContext = context.applicationContext

        // Plant all Timber trees
        Timber.plant(VerboseDebugTree())
        Timber.plant(FileLoggingTree(context))
        Timber.plant(CrashReportingTree())

        // Set up global exception handler
        setupGlobalExceptionHandler()

        Timber.i("ProductionLogger initialized successfully")
    }

    private fun setupGlobalExceptionHandler() {
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            Timber.e(throwable, "FATAL UNCAUGHT EXCEPTION on thread: ${thread.name}")
            logEntry(LogEntry(
                level = LogEntry.LogLevel.FATAL,
                tag = "UncaughtException",
                message = "Fatal crash on thread ${thread.name}",
                throwable = throwable,
                metadata = mapOf(
                    "thread_name" to thread.name,
                    "thread_id" to thread.id,
                    "thread_state" to thread.state.name
                )
            ))
            flushLogs()
            defaultHandler?.uncaughtException(thread, throwable)
        }
    }

    fun logEntry(entry: LogEntry) {
        logBuffer.add(entry)
        if (logBuffer.size >= BUFFER_FLUSH_SIZE) {
            flushLogs()
        }
    }

    fun flushLogs() {
        executor.execute {
            try {
                val logFile = File(appContext.filesDir, LOG_FILE_NAME)

                // Rotate log file if too large
                if (logFile.exists() && logFile.length() > MAX_LOG_FILE_SIZE) {
                    val backupFile = File(appContext.filesDir, "production_logs_backup.txt")
                    if (backupFile.exists()) backupFile.delete()
                    logFile.renameTo(backupFile)
                }

                FileWriter(logFile, true).use { writer ->
                    while (logBuffer.isNotEmpty()) {
                        val entry = logBuffer.poll()
                        entry?.let {
                            writer.appendLine(it.formatted())
                        }
                    }
                    writer.flush()
                }
            } catch (e: Exception) {
                Log.e("ProductionLogger", "Failed to flush logs to file", e)
            }
        }
    }

    fun getLogFile(): File = File(appContext.filesDir, LOG_FILE_NAME)

    fun getRecentLogs(count: Int = 100): List<String> {
        val logFile = getLogFile()
        if (!logFile.exists()) return emptyList()
        return logFile.readLines().takeLast(count)
    }

    fun clearLogs() {
        executor.execute {
            val logFile = getLogFile()
            if (logFile.exists()) logFile.delete()
        }
    }
}

// ============================================================
// Verbose Debug Tree - Detailed console output
// ============================================================
class VerboseDebugTree : Timber.DebugTree() {

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val enhancedMessage = buildString {
            append("[${Thread.currentThread().name}] ")
            append(message)
            if (t != null) {
                append("\n--- Stack Trace ---\n")
                val sw = StringWriter()
                t.printStackTrace(PrintWriter(sw))
                append(sw.toString())
                append("--- End Stack Trace ---")
            }
        }
        super.log(priority, "PROD_$tag", enhancedMessage, t)
    }

    override fun createStackElementTag(element: StackTraceElement): String {
        return "${element.className.substringAfterLast('.')}.${element.methodName}:${element.lineNumber}"
    }
}

// ============================================================
// File Logging Tree - Persistent file-based logging
// ============================================================
class FileLoggingTree(private val context: Context) : Timber.Tree() {

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val level = when (priority) {
            Log.VERBOSE -> LogEntry.LogLevel.VERBOSE
            Log.DEBUG -> LogEntry.LogLevel.DEBUG
            Log.INFO -> LogEntry.LogLevel.INFO
            Log.WARN -> LogEntry.LogLevel.WARN
            Log.ERROR -> LogEntry.LogLevel.ERROR
            Log.ASSERT -> LogEntry.LogLevel.FATAL
            else -> LogEntry.LogLevel.DEBUG
        }

        ProductionLogger.logEntry(LogEntry(
            level = level,
            tag = tag ?: "Unknown",
            message = message,
            throwable = t
        ))
    }
}

// ============================================================
// Crash Reporting Tree - Captures errors for crash reporting
// ============================================================
class CrashReportingTree : Timber.Tree() {

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (priority < Log.WARN) return

        // In production, this would send to Crashlytics, Sentry, etc.
        // For now, we ensure all warnings and errors are captured
        val severity = if (priority >= Log.ERROR) "ERROR" else "WARNING"
        Log.println(priority, "CrashReport",
            "[$severity] $tag: $message${t?.let { " | Exception: ${it.javaClass.simpleName}: ${it.message}" } ?: ""}")
    }
}

