// Authentication Logger
// ============================================================
object AuthLogger {

    private const val TAG = "AuthLogger"

    fun logLoginAttempt(
        username: String,
        method: String = "password",
        ipAddress: String? = null,
        userAgent: String? = null
    ) {
        Timber.tag(TAG).v(
            "LOGIN_ATTEMPT | user=%s | method=%s | ip=%s | userAgent=%s | timestamp=%d",
            maskSensitiveData(username),
            method,
            ipAddress ?: "unknown",
            userAgent ?: "unknown",
            System.currentTimeMillis()
        )

        ProductionLogger.logEntry(LogEntry(
            level = LogEntry.LogLevel.INFO,
            tag = TAG,
            message = "Login attempt initiated",
            metadata = mapOf(
                "username" to maskSensitiveData(username),
                "auth_method" to method,
                "ip_address" to ipAddress,
                "user_agent" to userAgent,
                "event_type" to "LOGIN_ATTEMPT"
            )
        ))
    }

    fun logLoginSuccess(
        username: String,
        userId: String,
        method: String = "password",
        sessionId: String? = null,
        tokenExpiry: Long? = null
    ) {
        Timber.tag(TAG).i(
            "LOGIN_SUCCESS | user=%s | userId=%s | method=%s | sessionId=%s | tokenExpiry=%s",
            maskSensitiveData(username),
            userId,
            method,
            sessionId?.take(8)?.plus("...") ?: "none",
            tokenExpiry?.let { SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US).format(Date(it)) } ?: "none"
        )

        ProductionLogger.logEntry(LogEntry(
            level = LogEntry.LogLevel.INFO,
            tag = TAG,
            message = "Login successful",
            metadata = mapOf(
                "username" to maskSensitiveData(username),
                "user_id" to userId,
                "auth_method" to method,
                "session_id" to sessionId?.take(8),
                "token_expiry" to tokenExpiry,
                "event_type" to "LOGIN_SUCCESS"
            )
        ))
    }

    fun logLoginFailure(
        username: String,
        reason: String,
        method: String = "password",
        errorCode: Int? = null,
        exception: Throwable? = null,
        attemptCount: Int = 0
    ) {
        Timber.tag(TAG).w(
            exception,
            "LOGIN_FAILED | user=%s | reason=%s | method=%s | errorCode=%s | attempts=%d",
            maskSensitiveData(username),
            reason,
            method,
            errorCode?.toString() ?: "none",
            attemptCount
        )

        ProductionLogger.logEntry(LogEntry(
            level = LogEntry.LogLevel.WARN,
            tag = TAG,
            message = "Login failed: $reason",
            throwable = exception,
            metadata = mapOf(
                "username" to maskSensitiveData(username),
                "failure_reason" to reason,
                "auth_method" to method,
                "error_code" to errorCode,
                "attempt_count" to attemptCount,
                "event_type" to "LOGIN_FAILED"
            )
        ))
    }

    fun logLogout(userId: String, reason: String = "user_initiated") {
        Timber.tag(TAG).i("LOGOUT | userId=%s | reason=%s", userId, reason)

        ProductionLogger.logEntry(LogEntry(
            level = LogEntry.LogLevel.INFO,
            tag = TAG,
            message = "User logged out",
            metadata = mapOf(
                "user_id" to userId,
                "logout_reason" to reason,
                "event_type" to "LOGOUT"
            )
        ))
    }

    fun logTokenRefresh(userId: String, success: Boolean, error: Throwable? = null) {
        if (success) {
            Timber.tag(TAG).v("TOKEN_REFRESH_SUCCESS | userId=%s", userId)
        } else {
            Timber.tag(TAG).w(error, "TOKEN_REFRESH_FAILED | userId=%s", userId)
        }

        ProductionLogger.logEntry(LogEntry(
            level = if (success) LogEntry.LogLevel.VERBOSE else LogEntry.LogLevel.WARN,
            tag = TAG,
            message = if (success) "Token refresh successful" else "Token refresh failed",
            throwable = error,
            metadata = mapOf(
                "user_id" to userId,
                "success" to success,
                "event_type" to "TOKEN_REFRESH"
            )
        ))
    }

    fun logRegistrationAttempt(email: String, method: String = "email") {
        Timber.tag(TAG).i("REGISTRATION_ATTEMPT | email=%s | method=%s", maskEmail(email), method)

        ProductionLogger.logEntry(LogEntry(
            level = LogEntry.LogLevel.INFO,
            tag = TAG,
            message = "Registration attempt",
            metadata = mapOf(
                "email" to maskEmail(email),
                "registration_method" to method,
                "event_type" to "REGISTRATION_ATTEMPT"
            )
        ))
    }

    fun logPasswordResetRequest(email: String) {
        Timber.tag(TAG).i("PASSWORD_RESET_REQUEST | email=%s", maskEmail(email))
    }

    private fun maskSensitiveData(data: String): String {
        if (data.length <= 3) return "***"
        return data.take(2) + "*".repeat(data.length - 3) + data.takeLast(1)
    }

    private fun maskEmail(email: String): String {
        val parts = email.split("@")
        if (parts.size != 2) return "***@***"
        val localPart = parts[0]
        val domain = parts[1]
        val maskedLocal = if (localPart.length <= 2) "**" else localPart.take(1) + "*".repeat(localPart.length - 2) + localPart.takeLast(1)
        return "$maskedLocal@$domain"
    }
}

